import { type Task } from 'wasp/entities'
import { type GetTasks } from 'wasp/server/queries'

export const getTasks: GetTasks<{ overdueOnly?: boolean }, Task[]> = async (args, context) => {
  const { overdueOnly } = args
  return context.entities.Task.findMany({
    where: overdueOnly ? { dueDate: { lt: new Date() } } : {}
  })
}

