import React, { useState } from 'react'
import { useQuery, getTasks, createTask } from 'wasp/client/operations'
import './Main.css'

export const MainPage = () => {
  const [overdueOnly, setOverdueOnly] = useState(false)
  const { data: tasks, isLoading, error } = useQuery(getTasks, { overdueOnly })

  const [description, setDescription] = useState('')
  const [dueDate, setDueDate] = useState('')

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!description || !dueDate) return
    try {
      await createTask({ description, dueDate })
      setDescription('')
      setDueDate('')
    } catch (err: any) {
      alert('Error creating task: ' + err.message)
    }
  }

  return (
    <div className="container">
      <h1 className="title">Task Deadlines</h1>

      <div className="content">
        <form onSubmit={handleCreateTask} style={{ marginBottom: '2rem' }}>
          <input
            type="text"
            placeholder="Task description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            style={{ padding: '0.5rem', marginRight: '0.5rem' }}
          />
          <input
            type="datetime-local"
            value={dueDate}
            onChange={(e) => setDueDate(e.target.value)}
            style={{ padding: '0.5rem', marginRight: '0.5rem' }}
          />
          <button type="submit" className="button button-filled">Add Task</button>
        </form>

        <div className="filter" style={{ marginBottom: '2rem' }}>
          <label>
            <input
              type="checkbox"
              checked={overdueOnly}
              onChange={(e) => setOverdueOnly(e.target.checked)}
            />
            {' '}Show Overdue Only
          </label>
        </div>

        {isLoading && <div>Loading tasks...</div>}
        {error && <div>Error: {error.message}</div>}

        {tasks && (
          <ul style={{ listStyle: 'none', padding: 0 }}>
            {tasks.map((task) => (
              <li key={task.id} style={{ marginBottom: '1rem', borderBottom: '1px solid #ccc', paddingBottom: '0.5rem' }}>
                <strong>{task.description}</strong> - {new Date(task.dueDate).toLocaleString()}
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  )
}

